877	                            if (isLineBreak(text.charCodeAt(pos))) {
878	                                hasTrailingNewLine = true;
879	                                break;
880	                            }
881	                            pos++;
882	                        }
883	                    }
884	                    else {
885	                        while (pos < text.length) {
886	                            if (text.charCodeAt(pos) === CharacterCodes.asterisk && text.charCodeAt(pos + 1) === CharacterCodes.slash) {
887	                                pos += 2;
888	                                break;
889	                            }
890	                            pos++;
891	                        }
892	                    }
893	
894	                    if (collecting) {
