711	function formatCodeSpan(file: SourceFile, start: number, length: number, indent: string, squiggleColor: ForegroundColorEscapeSequences, host: FormatDiagnosticsHost) {
712	    const { line: firstLine, character: firstLineChar } = getLineAndCharacterOfPosition(file, start);
713	    const { line: lastLine, character: lastLineChar } = getLineAndCharacterOfPosition(file, start + length);
714	    const lastLineInFile = getLineAndCharacterOfPosition(file, file.text.length).line;
715	
716	    const hasMoreThanFiveLines = (lastLine - firstLine) >= 4;
717	    let gutterWidth = (lastLine + 1 + "").length;
718	    if (hasMoreThanFiveLines) {
719	        gutterWidth = Math.max(ellipsis.length, gutterWidth);
720	    }
721	
722	    let context = "";
723	    for (let i = firstLine; i <= lastLine; i++) {
724	        context += host.getNewLine();
725	        // If the error spans over 5 lines, we'll only show the first 2 and last 2 lines,
726	        // so we'll skip ahead to the second-to-last line.
727	        if (hasMoreThanFiveLines && firstLine + 1 < i && i < lastLine - 1) {
728	            context += indent + formatColorAndReset(ellipsis.padStart(gutterWidth), gutterStyleSequence) + gutterSeparator + host.getNewLine();
729	            i = lastLine - 1;
730	        }
731	
732	        const lineStart = getPositionOfLineAndCharacter(file, i, 0);
733	        const lineEnd = i < lastLineInFile ? getPositionOfLineAndCharacter(file, i + 1, 0) : file.text.length;
734	        let lineContent = file.text.slice(lineStart, lineEnd);
735	        lineContent = lineContent.trimEnd(); // trim from end
736	        lineContent = lineContent.replace(/\t/g, " "); // convert tabs to single spaces
737	
738	        // Output the gutter and the actual contents of the line.
739	        context += indent + formatColorAndReset((i + 1 + "").padStart(gutterWidth), gutterStyleSequence) + gutterSeparator;
740	        context += lineContent + host.getNewLine();
741	
742	        // Output the gutter and the error span for the line using tildes.
743	        context += indent + formatColorAndReset("".padStart(gutterWidth), gutterStyleSequence) + gutterSeparator;
744	        context += squiggleColor;
745	        if (i === firstLine) {
746	            // If we're on the last line, then limit it to the last character of the last line.
747	            // Otherwise, we'll just squiggle the rest of the line, giving 'slice' no end position.
748	            const lastCharForLine = i === lastLine ? lastLineChar : undefined;
749	
750	            context += lineContent.slice(0, firstLineChar).replace(/\S/g, " ");
751	            context += lineContent.slice(firstLineChar, lastCharForLine).replace(/./g, "~");
752	        }
753	        else if (i === lastLine) {
754	            context += lineContent.slice(0, lastLineChar).replace(/./g, "~");
755	        }
756	        else {
757	            // Squiggle the entire line.
758	            context += lineContent.replace(/./g, "~");
759	        }
760	        context += resetEscapeSequence;
761	    }
762	    return context;
763	}
